sql:
SELECT AVG(total) AS average_total_spent
FROM orders
WHERE order_date BETWEEN '2016-10-01' AND '2016-10-31';

SELECT SUM(total) AS total_cost_of_delivered_orders
FROM orders
WHERE status = 'delivered';

SELECT AVG(total) AS average_total_cost
FROM orders
WHERE status = 'delivered';

external_knowledge:
- 'plastic' is a common term used to refer to credit cards;
- 'last quarter' refers to the period between October 1, 2023, and December 31, 2023;
- 'fulfilled their purchases' means the orders have a status of 'delivered'.
